float c2 = texture(sampler_fc_main, uv2).x;
float c3 = texture(sampler_fc_main, uv3).x;
float c4 = texture(sampler_fc_main, uv4).x;


ret.x = max(max(c1,c2),max(c3,c4))*1.1 - 0.00;
//ret = 0;

vec2 zoom =1.68 + q2;
