 vec2 my_uv = (vUvOriginal-0.5)*zoom;
 my_uv = vec2(my_uv.x*my_uv.x - my_uv.y*my_uv.y, 2*my_uv.x*my_uv.y) + c; // u -> u^2 + c

ret.y = texture(sampler_fc_main, my_uv).y + texture(sampler_fc_main, 0.5+ (vUv-0.5)*4).z;

ret.z = texture(sampler_fc_main, (vUv-0.5)*3 + vec2(1.4,0)).y*1.2;

float si = q3; // sin(w)
