vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvs = (vUv-0.5)*2 + vec2(q11,q12);
uvb = (vUv-0.5)*0.5 + 0.5 - (vec2(q11,q12)-0.5)*0.5;

c = pow(fract(q1),0.5);
uv_i = mix(uvs,vUv,c);
uv_ii = mix(vUv,uvb,c);

float p = texture(sampler_fc_main,uv_i).x*c+texture(sampler_fc_main,uv_ii).x*(1-c);

float1 si = q5; // sin(w)
float1 co = q6; // cos(w)
vec2 scale = 0.5;

vec2 uv6 = (vUv-0.5)*uAspect.xy*2;
       uv6 = scale*vec2( co*uv6.x - si*uv6.y, si*uv6.x + co*uv6.y); // rotation
       uv6 = 0.5 + uv6*uAspect.zw + vec2(q7,q8);

       uv6 = fract(uv6);

ret.y = texture(sampler_fc_main,uv6).y;

vec2 zoom =1.68 + q2;
vec2 c = vec2(0.36,0.72);

 vec2 my_uv = (vUvOriginal-0.5)*zoom;
 my_uv = vec2(my_uv.x*my_uv.x - my_uv.y*my_uv.y, 2*my_uv.x*my_uv.y) + c; // u -> u^2 + c


    vec2 d = uTexSize.zw*4;
    vec2 uv_z = fract(0.5+(my_uv-0.5)*0.7);

    vec3 dx = ( GetBlur1(uv_z+vec2(1,0)*d)-GetBlur1(uv_z-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(uv_z+vec2(0,1)*d)-GetBlur1(uv_z-vec2(0,1)*d) );

vec3 c1 = mix(0,vec3(0,0.5,0.8),texture(sampler_fc_main,uv6).y);
vec3 c2 = mix(vec3(0.4,0,0.1),vec3(1,1,0),GetBlur1(uv6 + vec2(dx.z,dy.z)*0.1).y);
ret = mix(mix(c1,c2,texture(sampler_fc_main,uv_z).z),1,p);

  fragColor = ret;
}
